          text = text.replace(/\[size=\d\]/ig, '').replace(/\[\/size\]/ig, '');
          text = text.replace(/\[font=.+?\]/ig, '').replace(/\[\/font\]/ig, '');
          text = text.replace(/\[color=.+?\]/ig, '').replace(/\[\/color\]/ig, '');
