          text = text.replace(/\[b\]\s*/ig, '**').replace(/\s*\[\/b\]/ig, '**');
          text = text.replace(/\[i\]\s*/ig, '*').replace(/\s*\[\/i\]/ig, '*');
          text = text.replace(/\[url=([^\]]*?)\](.*?)\[\/url\]/ig, '[$2]($1)');
          text = text.replace(/\[quote\](.*?)\[\/quote\]/isg, (m, n) => '> ' + n.split('\n').join('\n> ') + '\n\n');
